+      if (questions.length > 0) {
+        lines.push("### Open Questions\n");
+        for (const q of questions) {
+          const check = q.status === "pending" ? "[ ]" : "[x]";
+          lines.push(`- ${check} **${q.title}** — ${q.description}`);
+        }
+        lines.push("");
+      }
+
+      if (planIterations.length > 0) {
